// Verificar si Tailwind CSS se cargó correctamente
function checkTailwindLoaded() {
    // Crear un elemento de prueba para verificar si Tailwind está disponible
    const testElement = document.createElement('div');
    testElement.className = 'block';
    testElement.style.display = 'none';
    document.body.appendChild(testElement);
    
    const computedStyle = window.getComputedStyle(testElement);
    const isLoaded = computedStyle.display === 'block';
    
    document.body.removeChild(testElement);
    return isLoaded;
}

// Cargar CSS alternativo si Tailwind falló
function loadFallbackCSS() {
    console.warn('Tailwind CSS CDN no se cargó correctamente, cargando CSS alternativo');
    const link = document.createElement('link');
    link.rel = 'stylesheet';
    link.href = 'https://assets-us-01.kc-usercontent.com/b2956330-c34f-0064-2c6f-27bd5c0147fc/90aa08d0-0e19-4485-8ddf-37920bc2e243/tailwindoutput.css'; // Cambia por tu archivo CSS
    document.head.appendChild(link);
}

// Verificar cuando la página esté lista
document.addEventListener('DOMContentLoaded', function() {
    setTimeout(() => {
        if (!checkTailwindLoaded()) {
            loadFallbackCSS();
        }else{
            console.log('Tailwind CSS CDN se cargó correctamente');
        }
    }, 100);
});

// Manejar error del script directamente
const tailwindScript = document.querySelector('script[src*="tailwindcss"]');
if (tailwindScript) {
    tailwindScript.addEventListener('error', function() {
        console.error('Error al cargar Tailwind CSS, cargando CSS alternativo');
        loadFallbackCSS();
    });
}

/**
 * FontAwesome Loader - Versión Ultra Minimalista
 * La forma más simple de cargar FontAwesome con 1 solo archivo
 */

